UPDATE t_wms_location
SET useyn = 'N'
	, ymdhms_d = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, MEMO_D = 'INCOMING_D'
	, LOGINID_D = #{loginid}
WHERE USEYN = 'Y'
AND BARCODE = #{barcode}
AND FACTORY = #{factory}
AND STORAGE = #{storage}

UPDATE t_wms_inbound
SET useyn = 'N'
	, ymdhms_d = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, LOGINID_D = #{loginid}

	, MEMO2 = #{reason}

WHERE IID = #{iid}

UPDATE T_WMS_STOCK
SET USEYN = 'N'
	, YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, MEMO_D = 'INCOMING_D'
	, LOGINID_D = #{loginid}
WHERE USEYN = 'Y'
AND SDATE = #{date}
AND FACTORY = #{factory}
AND STORAGE = #{storage}
AND KIND = 'INCOMING'
AND BARCODE = #{barcode}

UPDATE t_wms_outbound
SET useyn = 'N'
	, ymdhms_d = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, LOGINID_D = #{loginid}

	, MEMO2 = #{reason}

WHERE IID = #{iid}

UPDATE T_WMS_STOCK
SET USEYN = 'N'
	, YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
	, MEMO_D = 'LOAD_D'
	, LOGINID_D = #{loginid}
WHERE USEYN = 'Y'
AND SDATE = #{date}
AND FACTORY = #{factory}
AND KIND = 'LOAD'
AND BARCODE = #{barcode}

mapper.select:
SELECT a.sdate AS SDATE, a.loginid AS LOGINID, a.factory AS FACTORY, a.storage AS STORAGE, a.custcode AS custcode, a.custname AS custname, c.subname AS CAR, a.itemcode AS ITEMCODE, b.spec AS OITEMCODE, b.itemname AS ITEMNAME, a.qty AS QTY, a.barcode AS BARCODE, a.invoiceno AS INVOICENO, a.intf_yn AS INTF_YN, a.mes_key AS MESKEY, a.ymdhms AS YMDHMS, SUBSTR(a.ymdhms, 9, 2) || ':' || SUBSTR(a.ymdhms, 11, 2) AS HHMM, a.bdate AS BDATE, a.iid AS IID, a.tradebarcode,
/* 전체 개수 - 모든 행에 반복 */ (SELECT COUNT(*) FROM t_wms_inbound a2 LEFT JOIN t_mi_item b2 ON a2.itemcode = b2.itemcode LEFT JOIN t_mi_typesub c2 ON b2.carno = c2.subcode AND c2.typecode = 'MI041' WHERE 1=1 AND a2.source = 'INCOMING'
) AS TOTALCOUNT,
/* 총 수량 - 모든 행에 반복 */ (SELECT NVL(SUM(a2.qty), 0) FROM t_wms_inbound a2 LEFT JOIN t_mi_item b2 ON a2.itemcode = b2.itemcode LEFT JOIN t_mi_typesub c2 ON b2.carno = c2.subcode AND c2.typecode = 'MI041' WHERE 1=1 AND a2.source = 'INCOMING'
) AS TOTALQTY
FROM t_wms_inbound a LEFT JOIN t_mi_item b ON a.itemcode = b.itemcode LEFT JOIN t_mi_typesub c ON b.carno = c.subcode AND c.typecode = 'MI041' WHERE 1=1 AND a.source = 'INCOMING'
ORDER BY a.sdate DESC, a.ymdhms DESC, a.itemcode, a.barcode, a.loginid
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

