UPDATE T_WMS_SEQUENCE
SET USEYN = 'N',
	YMDHMS_D = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
WHERE SDATE = #{sdate}
  AND LINE = #{line}
  AND USEYN = 'Y'
